#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Create an MLflow experiment
 *
 * This example demonstrates:
 * - Creating an MLflow experiment
 * - Setting experiment tags
 * - Getting experiment details
 * - Deleting an experiment
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 *
 * Usage:
 *   npx ts-node examples/workspace/ml/create-experiment.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    const experimentName = `/Shared/sdk-experiment-${Date.now()}`;

    console.log(`Creating MLflow experiment: ${experimentName}`);

    try {
        // Create experiment with tags
        const experiment = await client.experiments.createExperiment({
            name: experimentName,
            tags: [
                {key: "team", value: "data-science"},
                {key: "project", value: "sdk-examples"},
                {key: "created_by", value: "databricks-sdk-js"},
            ],
        });

        console.log(`✓ Experiment created successfully`);
        console.log(`  Experiment ID: ${experiment.experiment_id}`);
        console.log(`  Name: ${experimentName}`);

        // Get experiment details
        const experimentDetails = await client.experiments.getExperiment({
            experiment_id: experiment.experiment_id!,
        });

        console.log(`\nExperiment Details:`);
        console.log(
            `  Artifact Location: ${experimentDetails.experiment?.artifact_location || "N/A"}`
        );
        console.log(
            `  Lifecycle Stage: ${experimentDetails.experiment?.lifecycle_stage}`
        );
        console.log(
            `  Creation Time: ${experimentDetails.experiment?.creation_time ? new Date(experimentDetails.experiment.creation_time).toISOString() : "N/A"}`
        );
        console.log(
            `  Last Update Time: ${experimentDetails.experiment?.last_update_time ? new Date(experimentDetails.experiment.last_update_time).toISOString() : "N/A"}`
        );

        if (experimentDetails.experiment?.tags) {
            console.log(`  Tags:`);
            for (const tag of experimentDetails.experiment.tags) {
                console.log(`    ${tag.key}: ${tag.value}`);
            }
        }

        // Search for experiments (demonstrates search API)
        console.log(`\nSearching for experiments...`);

        const experiments: any[] = [];
        for await (const exp of client.experiments.searchExperiments({
            filter: `name LIKE '${experimentName}'`,
            max_results: 10,
        })) {
            experiments.push(exp);
        }

        if (experiments.length > 0) {
            const expTable = experiments.map((exp) => ({
                "Name": exp.name,
                "Experiment ID": exp.experiment_id,
            }));
            console.table(expTable);
        } else {
            console.log(`  No experiments found`);
        }

        // Cleanup: Delete the experiment
        console.log(
            `\nCleaning up: deleting experiment ${experiment.experiment_id}`
        );
        await client.experiments.deleteExperiment({
            experiment_id: experiment.experiment_id!,
        });
        console.log(`✓ Experiment deleted`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
